
package com.example.taxgap.domain.dto; import java.util.List; public class TransactionUploadResponse { private int received; private int success; private int failed; private List<String> failedTransactionIds; public TransactionUploadResponse(){} public TransactionUploadResponse(int r,int s,int f,List<String> ids){received=r;success=s;failed=f;failedTransactionIds=ids;} public int getReceived(){return received;} public void setReceived(int v){received=v;} public int getSuccess(){return success;} public void setSuccess(int v){success=v;} public int getFailed(){return failed;} public void setFailed(int v){failed=v;} public List<String> getFailedTransactionIds(){return failedTransactionIds;} public void setFailedTransactionIds(List<String> v){failedTransactionIds=v;} }
